  'nacionalidad': { es: 'Para renovar el pasaporte, debes indicar tu nacionalidad en el formulario.', ja: 'パスポートを更新するには、申請書に国籍を記入する必要がある。' },
  'nada': { es: 'No tengo nada que hacer esta tarde, así que puedo ayudarte.', ja: '今日の午後は特にやることがないから、手伝えるよ。' },
  'nadie': { es: 'Llamé a la puerta varias veces, pero nadie respondió.', ja: '何度もドアをノックしたが、誰も応答しなかった。' },
  'nal': { es: 'El tribunal nal se encargó de resolver el conflicto entre las dos provincias.', ja: '国家裁判所が二つの州間の紛争の解決を担った。' },
  'narrar': { es: 'El escritor narraba sus aventuras con una voz pausada y llena de detalles.', ja: 'その作家はゆっくりとした声で、細部まで丁寧に自分の冒険を語った。' },
  'natural': { es: 'Es natural que los niños cometan errores mientras aprenden.', ja: '子供たちが学ぶ過程でミスを犯すのは当然のことだ。' },
  'naturaleza': { es: 'Me encanta salir a caminar por la naturaleza los fines de semana.', ja: '週末に自然の中を歩くのが大好きだ。' },
  'naufragio': { es: 'Los supervivientes del naufragio fueron rescatados después de dos días a la deriva.', ja: '難破の生存者たちは2日間漂流した末に救助された。' },
  'navaja': { es: 'El cocinero abrió la navaja con destreza para preparar los ingredientes.', ja: '料理人は食材を準備するために折りたたみナイフを手際よく開いた。' },
  'Navidad': { es: 'Pasamos la Navidad en familia comiendo turrón y viendo las luces de la ciudad.', ja: '家族でトゥロンを食べ、街のイルミネーションを見ながらクリスマスを過ごした。' },
  'necedad': { es: 'Fue una necedad gastar todos los ahorros en un solo día.', ja: '全貯金を一日で使い果たすとは愚かな行為だった。' },
  'necesidad': { es: 'La necesidad de ahorrar energía se ha vuelto urgente ante el cambio climático.', ja: '気候変動を前に、エネルギーを節約する必要性が緊急のものとなっている。' },
  'nefasto': { es: 'El accidente tuvo consecuencias nefastas para toda la comunidad.', ja: 'その事故は地域社会全体に悲惨な影響をもたらした。' },
  'negar': { es: 'El sospechoso negó haber estado en el lugar del crimen aquella noche.', ja: '容疑者はその夜、犯行現場にいたことを否定した。' },
  'negociación': { es: 'Las negociaciones entre los dos países terminaron con un acuerdo de paz.', ja: '両国間の交渉は平和協定で終結した。' },
  'negociar': { es: 'El sindicato y la empresa negociaron un aumento de sueldo durante tres meses.', ja: '労働組合と会社は3か月間にわたって賃上げを交渉した。' },
  'negocio': { es: 'Mi tío abrió un negocio de comida en el centro de la ciudad.', ja: '叔父は市の中心部で飲食店を開いた。' },
  'nene': { es: 'La nene se quedó dormida en los brazos de su madre.', ja: '赤ちゃんはお母さんの腕の中で眠ってしまった。' },
  'nervio': { es: 'El médico dijo que tenía el nervio ciático inflamado.', ja: '医者は坐骨神経が炎症を起こしていると言った。' },
  'nervioso': { es: 'Estaba muy nervioso antes de salir al escenario por primera vez.', ja: '初めて舞台に出る前、彼はとても緊張していた。' },
  'neto': { es: 'Mi salario neto después de impuestos es bastante menor que el bruto.', ja: '税引き後の手取り給与は額面よりかなり少ない。' },
  'neumático': { es: 'Se me pinchó el neumático trasero en medio de la autopista.', ja: '高速道路の真ん中で後ろのタイヤがパンクした。' },
