  'nieto': { es: 'El abuelo lleva a su nieto al parque todos los sábados.', ja: '祖父は毎週土曜日に孫を公園に連れて行く。' },
  'niña': { es: 'La niña aprendió a leer antes de cumplir los cinco años.', ja: 'その女の子は5歳になる前に読み方を覚えた。' },
  'niñez': { es: 'Guarda muy buenos recuerdos de su niñez en el pueblo.', ja: '彼女は村での幼少期についてとてもよい思い出を持っている。' },
  'níquel': { es: 'La moneda de cinco centavos de dólar se llama nickel y está hecha principalmente de cobre.', ja: '5セント硬貨はニッケルと呼ばれるが、主に銅でできている。' },
  'nítido': { es: 'La fotografía salió muy nítida gracias a la nueva cámara.', ja: '新しいカメラのおかげで写真がとても鮮明に撮れた。' },
