  'nobleza': { es: 'La nobleza de su carácter se reveló cuando donó toda su herencia a obras benéficas.', ja: '遺産をすべて慈善事業に寄付したとき、彼の人格の気高さが明らかになった。' },
  'nombramiento': { es: 'El nombramiento del nuevo director fue anunciado en una reunión del consejo.', ja: '新しい理事長の任命は理事会の会議で発表された。' },
  'nombrar': { es: 'El presidente nombró a una experta en economía como ministra de finanzas.', ja: '大統領は経済の専門家を財務大臣に任命した。' },
  'norma': { es: 'Todos los empleados deben cumplir con las normas de seguridad del trabajo.', ja: 'すべての従業員は職場の安全規則を遵守しなければならない。' },
  'normal': { es: 'Es completamente normal sentirse nervioso antes de una entrevista de trabajo.', ja: '就職面接の前に緊張するのはまったく普通のことだ。' },
  'norte': { es: 'El norte del país es conocido por sus montañas nevadas y su clima frío.', ja: 'その国の北部は雪を頂く山々と寒冷な気候で知られている。' },
  'norteamericano': { es: 'Mi vecino norteamericano me enseñó muchas expresiones del inglés coloquial.', ja: '北米出身の隣人が、英語の口語表現をたくさん教えてくれた。' },
  'nos': { es: 'El profesor nos explicó la diferencia entre el pretérito indefinido y el imperfecto.', ja: '先生は私たちに、点過去と線過去の違いを説明してくれた。' },
