  'nota': { es: 'Saqué una nota muy alta en el examen de matemáticas gracias a que estudié mucho.', ja: 'たくさん勉強したおかげで、数学の試験でとても高い点数を取ることができた。' },
  'notar': { es: 'Noté que algo había cambiado en su actitud desde la última vez que nos vimos.', ja: '前回会ったときから彼の態度に何か変化があったことに気づいた。' },
