  'notificar': { es: 'El banco me notificó por correo electrónico que había un movimiento inusual en mi cuenta.', ja: '銀行から、私の口座に不審な動きがあったというメールで通知が来た。' },
  'novato': { es: 'Como soy novato en la cocina, a veces cometo errores básicos con las recetas.', ja: '料理は初心者なので、レシピで基本的なミスをしてしまうことがある。' },
