  'novelista': { es: 'La novelista colombiana presentó su nuevo libro en la feria internacional del libro de Madrid.', ja: 'コロンビア人の女性小説家がマドリードの国際ブックフェアで新作を発表した。' },
  'noveno': { es: 'Llegamos al noveno piso del edificio y desde allí se veía toda la ciudad.', ja: 'ビルの9階に着くと、そこから街全体が見渡せた。' },
  'noventa': { es: 'Mi abuela tiene noventa años y todavía camina todos los días por el parque.', ja: '私の祖母は90歳で、今でも毎日公園を散歩している。' },
  'novia': { es: 'Mi novia y yo llevamos tres años juntos y el mes que viene nos comprometemos.', ja: '彼女と付き合って3年になり、来月婚約する予定だ。' },
  'novio': { es: 'El novio de mi hermana le regaló flores el día de su aniversario.', ja: '姉の彼氏が記念日に花をプレゼントした。' },
