  'nuestro': { es: 'Nuestro equipo ganó el campeonato después de meses de entrenamiento intensivo.', ja: '私たちのチームは数か月間の集中トレーニングの末、選手権で優勝した。' },
  'nueva': { es: '¿Has oído la nueva? Parece que van a abrir un restaurante japonés en nuestra calle.', ja: 'もう聞いた？私たちの通りに日本料理のレストランがオープンするらしいよ。' },
