  'nutrición': { es: 'Una buena nutrición durante la infancia es clave para el desarrollo físico y mental.', ja: '幼少期における適切な栄養摂取は、身体的・精神的な発達の鍵である。' },
  'nutritivo': { es: 'Los frutos secos son muy nutritivos y se pueden tomar como snack saludable.', ja: 'ナッツ類は非常に栄養豊富で、健康的なスナックとして食べることができる。' },
  'o': { es: '¿Prefieres el café o el té por las mañanas?', ja: '朝はコーヒーと紅茶、どちらが好きですか？' },
  'oasis': { es: 'El pequeño café del barrio era un oasis de tranquilidad en medio del ruido urbano.', ja: 'その町の小さなカフェは、都会の喧騒の中の静けさのオアシスだった。' },
  'obedecer': { es: 'El perro obedece todas las órdenes de su dueño sin dudarlo.', ja: 'その犬は飼い主のすべての命令に迷わず従う。' },
  'obediencia': { es: 'La obediencia ciega puede ser tan peligrosa como la rebeldía sin motivo.', ja: '盲目的な服従は、理由のない反抗と同様に危険なこともある。' },
