  'objetar': { es: 'Nadie objetó nada cuando se propuso cambiar el horario de la reunión.', ja: '会議の時間変更が提案されたとき、誰も何も反対しなかった。' },
  'objetivo': { es: 'Nuestro principal objetivo este año es aumentar las ventas en un veinte por ciento.', ja: '今年の主な目標は売上を20パーセント伸ばすことである。' },
  'objeto': { es: 'Encontraron varios objetos extraños en el fondo del lago.', ja: '湖の底でいくつかの奇妙な物体が発見された。' },
  'obligación': { es: 'Tienes la obligación de informar al jefe sobre cualquier problema grave.', ja: '深刻な問題が発生した場合は上司に報告する義務がある。' },
  'obligar': { es: 'La tormenta nos obligó a cancelar el viaje de fin de semana.', ja: '嵐のせいで週末の旅行をキャンセルせざるを得なくなった。' },
  'obligatorio': { es: 'El uso del casco es obligatorio para todos los motoristas.', ja: 'ヘルメットの着用はすべてのオートバイ乗りに義務づけられている。' },
