  'obscuro': { es: 'En aquel obscuro pasillo no había ninguna ventana ni lámpara.', ja: 'その暗い廊下には窓も電灯もなかった。' },
  'observar': { es: 'Los científicos observaron el comportamiento de los delfines durante varias semanas.', ja: '科学者たちは数週間にわたってイルカの行動を観察した。' },
  'observación': { es: 'El médico hizo una observación importante sobre el estado del paciente.', ja: '医師は患者の状態について重要な指摘を行った。' },
  'observatorio': { es: 'Desde el observatorio astronómico se pueden ver miles de estrellas en noches despejadas.', ja: '天文台からは、晴れた夜に何千もの星を見ることができる。' },
  'obsesión': { es: 'Su obsesión por el orden le impedía disfrutar de los pequeños placeres de la vida.', ja: '整理整頓への強迫観念が、彼女が人生の小さな喜びを楽しむことを妨げていた。' },
  'obstáculo': { es: 'La falta de recursos económicos fue el mayor obstáculo para llevar a cabo el proyecto.', ja: '資金不足がプロジェクト実行の最大の障害だった。' },
  'obstante': { es: 'No obstante las dificultades, el equipo logró terminar el trabajo a tiempo.', ja: '困難にもかかわらず、チームは仕事を時間通りに終えることができた。' },
  'obtener': { es: 'Después de varios intentos, finalmente obtuvo el permiso para construir la casa.', ja: '何度か試みた末に、ついに家を建てる許可を得た。' },
  'obvio': { es: 'Era obvio que no había dormido bien porque tenía ojeras muy marcadas.', ja: '目の下のくまがひどくて、よく眠れていないのは明らかだった。' },
  'ocasión': { es: 'Aprovechamos la ocasión de estar todos juntos para celebrar el aniversario de la empresa.', ja: '全員が揃った機会を活かして、会社の創立記念日を祝った。' },
  'ocaso': { es: 'Nos sentamos en la playa a contemplar el hermoso ocaso mientras el cielo se teñía de naranja.', ja: '空がオレンジ色に染まる中、美しい夕暮れを眺めながら浜辺に座った。' },
  'occidental': { es: 'Las culturas orientales y occidentales tienen perspectivas muy distintas sobre el concepto del tiempo.', ja: '東洋文化と西洋文化では、時間の概念について非常に異なる見方をしている。' },
  'occidente': { es: 'La filosofía de Occidente ha sido profundamente influenciada por los pensadores griegos.', ja: '西洋哲学はギリシャの思想家たちから深く影響を受けてきた。' },
  'ocio': { es: 'En sus ratos de ocio, le encanta leer novelas históricas y escuchar música clásica.', ja: '余暇の時間には、歴史小説を読んだりクラシック音楽を聴いたりするのが大好きだ。' },
  'octubre': { es: 'En octubre, los árboles del parque se visten de colores rojos y amarillos.', ja: '10月になると、公園の木々が赤や黄色の色に染まる。' },
  'ocultar': { es: 'Intentó ocultar su nerviosismo hablando con mucha seguridad ante el público.', ja: '聴衆の前で自信たっぷりに話すことで、緊張を隠そうとした。' },
  'oculto': { es: 'Detrás de esa sonrisa había un dolor oculto que nadie era capaz de ver.', ja: 'その笑顔の裏には、誰にも見えない隠れた痛みがあった。' },
  'ocupación': { es: 'En el formulario pedían indicar la ocupación actual y el nivel de estudios.', ja: '申請書には現在の職業と学歴を記入するよう求められていた。' },
  'ocupar': { es: 'Los manifestantes ocuparon la plaza central durante toda la noche para protestar.', ja: 'デモ参加者たちは抗議のため、一晩中中央広場を占拠した。' },
  'ochenta': { es: 'Mi abuela cumplió ochenta años y celebramos su cumpleaños con toda la familia.', ja: '祖母が80歳になり、家族全員でその誕生日を祝った。' },
  'ocho': { es: 'El tren sale a las ocho en punto, así que no podemos llegar tarde.', ja: '電車は8時ちょうどに出発するので、遅刻はできない。' },
  'odiar': { es: 'Odio tener que madrugar los lunes, pero no tengo más remedio.', ja: '月曜日に早起きしなければならないのが大嫌いだが、仕方がない。' },
  'odio': { es: 'El odio entre los dos bandos duró generaciones y causó mucho sufrimiento.', ja: '両派の間の憎しみは何世代にもわたって続き、多くの苦しみをもたらした。' },
  'oeste': { es: 'El sol se pone por el oeste y tiñe el horizonte de colores cálidos.', ja: '太陽は西に沈み、地平線を暖かい色に染める。' },
  'oficial': { es: 'El gobierno publicó un comunicado oficial para aclarar su posición ante la crisis.', ja: '政府は危機に対する立場を明確にするため、公式声明を発表した。' },
  'oficio': { es: 'La carpintería es un oficio que requiere mucha paciencia y habilidad manual.', ja: '大工仕事は多くの忍耐と手先の器用さを必要とする職人技だ。' },
  'oferta': { es: 'El supermercado tiene una oferta especial: tres latas de atún por el precio de dos.', ja: 'スーパーで特売がある。ツナ缶3つが2つ分の値段だ。' },
  'oído': { es: 'Tiene un oído musical extraordinario y puede reconocer cualquier nota de inmediato.', ja: '彼女は並外れた音楽的な耳を持っており、どんな音符もすぐに聞き分けられる。' },
  'oler': { es: 'Desde la cocina se podía oler el aroma del pan recién horneado.', ja: '台所から焼きたてのパンの香りが漂ってきた。' },
  'olivo': { es: 'En el jardín de la casa había un olivo centenario que daba una sombra agradable.', ja: '家の庭には百年以上たつオリーブの木があり、心地よい木陰を作っていた。' },
  'olor': { es: 'El olor a pan recién horneado llenó toda la casa.', ja: '焼きたてのパンの香りが家中に広がった。' },
  'olvido': { es: 'Con el paso del tiempo, el olvido borró aquella triste historia.', ja: '時が経つにつれて、忘却があの悲しい物語を消し去った。' },
  'ombligo': { es: 'El bebé se quedó dormido tocándose el ombligo.', ja: '赤ちゃんはへそを触りながら眠ってしまった。' },
