  'pecar': { es: 'El chef dijo que prefería pecar de exceso antes que servir porciones insuficientes.', ja: 'シェフは量が足りないよりも多すぎるほうがましだと言った。' },
  'pece': { es: 'En los textos antiguos, a veces se encontraba la palabra pece en lugar de pez.', ja: '古い文書では、pez の代わりに pece という語が見られることがある。' },
  'pecera': { es: 'Mi hermana tiene una pecera con varios peces de colores en su habitación.', ja: '姉の部屋には色とりどりの魚が入った金魚鉢がある。' },
  'pecho': { es: 'El nadador respiró profundamente y se lanzó al agua con el pecho bien abierto.', ja: 'その水泳選手は深く息を吸い、胸を大きく張って水に飛び込んだ。' },
  'peculiar': { es: 'Tiene un sentido del humor bastante peculiar que no todo el mundo entiende.', ja: '彼は誰もが理解できるわけではない、かなり独特のユーモアセンスを持っている。' },
  'pedazo': { es: 'Se le cayó el plato al suelo y se rompió en pedazos.', ja: 'お皿が床に落ちて粉々に割れた。' },
  'pedrada': { es: 'La ventana se rompió de una pedrada que lanzó un niño jugando en la calle.', ja: '通りで遊んでいた子どもが投げた石で窓ガラスが割れた。' },
  'pedido': { es: 'El pedido que hice por internet llegó antes de lo esperado.', ja: 'インターネットで注文した品が予想より早く届いた。' },
  'pedregoso': { es: 'El camino hacia la cima era muy pedregoso y tuvimos que ir con cuidado.', ja: '頂上までの道はとても石だらけで、慎重に進まなければならなかった。' },
  'pegar': { es: '¿Me puedes ayudar a pegar estas fotos en el álbum?', ja: 'このアルバムに写真を貼るのを手伝ってもらえますか？' },
  'pegamento': { es: 'El niño usó pegamento para unir las piezas del modelo de avión.', ja: '男の子は飛行機の模型のパーツをつなぐために接着剤を使った。' },
  'pegajoso': { es: 'Después de comer caramelos, tenía los dedos pegajosos.', ja: 'キャラメルを食べた後、指がベタベタになっていた。' },
  'peinado': { es: 'Fue a la peluquería para hacerse un peinado especial para la boda.', ja: '結婚式のために特別なヘアスタイルを作ってもらいに美容院へ行った。' },
  'peinar': { es: 'Todas las mañanas se peina frente al espejo antes de salir de casa.', ja: '毎朝、家を出る前に鏡の前で髪をとかしている。' },
  'peine': { es: 'Siempre lleva un peine en el bolsillo para arreglarse el pelo en cualquier momento.', ja: 'いつでも髪を整えられるよう、常にポケットにくしを持ち歩いている。' },
  'pelar': { es: 'Por favor, pela las patatas antes de echarlas a la olla.', ja: '鍋に入れる前にじゃがいもの皮をむいてください。' },
  'peldaño': { es: 'El niño subió los peldaños de la escalera de uno en uno.', ja: 'その子は階段の段を一段一段上っていった。' },
  'pelea': { es: 'Los dos hermanos tuvieron una pelea por el mando a distancia del televisor.', ja: '二人の兄弟はテレビのリモコンをめぐって喧嘩した。' },
  'pelear': { es: 'Los dos hermanos pelean constantemente por el mando del televisor.', ja: 'その二人の兄弟はテレビのリモコンをめぐっていつも喧嘩している。' },
  'película': { es: 'Ayer vimos una película de terror que nos dejó sin dormir.', ja: '昨日、怖くて眠れなくなるようなホラー映画を見た。' },
  'peligro': { es: 'El cartel advertía que había peligro de avalanchas en esa zona de montaña.', ja: 'その看板は、その山岳地帯では雪崩の危険があると警告していた。' },
  'peligroso': { es: 'Es peligroso cruzar la calle sin mirar a ambos lados.', ja: '両側を見ずに道路を横断するのは危険だ。' },
  'pelota': { es: 'Los niños jugaban a la pelota en el parque después del colegio.', ja: '子どもたちは放課後に公園でボール遊びをしていた。' },
  'peluca': { es: 'El actor llevaba una peluca rubia para interpretar a ese personaje histórico.', ja: 'その俳優はその歴史的人物を演じるために金髪のかつらをつけていた。' },
  'peluquero': { es: 'Mi peluquero me recomendó un nuevo champú para el cabello seco.', ja: '私の美容師が乾燥した髪向けの新しいシャンプーを勧めてくれた。' },
  'pelusa': { es: 'Encontré mucha pelusa debajo del sofá cuando lo moví para limpiar.', ja: '掃除のためにソファを動かしたら、下にたくさんの綿埃が溜まっていた。' },
