  'penal': { es: 'El jugador cometió una falta dentro del área y el árbitro pitó penal.', ja: '選手がペナルティエリア内でファウルをし、審判はペナルティキックを宣告した。' },
  'penalidad': { es: 'Los migrantes sufrieron grandes penalidades durante su largo viaje hacia el norte.', ja: '移民たちは北へ向かう長い旅の間、多くの苦難を経験した。' },
