  'penar': { es: 'Ella penó mucho tiempo por la pérdida de su madre.', ja: '彼女は母の死を長い間悲しみ続けた。' },
  'pendencia': { es: 'Ese bar tiene fama de ser lugar de pendencias los fines de semana.', ja: 'そのバーは週末に喧嘩が起きることで有名だ。' },
  'tendencia': { es: 'Hay una tendencia creciente a trabajar desde casa entre los jóvenes profesionales.', ja: '若いビジネスパーソンの間で在宅勤務をする傾向が高まっている。' },
