  'penetración': { es: 'La penetración de los teléfonos inteligentes en el mercado rural ha sido muy rápida.', ja: '農村市場へのスマートフォンの普及は非常に速かった。' },
  'penetrar': { es: 'La humedad penetró en las paredes del sótano durante las lluvias.', ja: '雨の間、湿気が地下室の壁に染み込んだ。' },
  'penitencia': { es: 'Como penitencia, el sacerdote le pidió que rezara tres oraciones.', ja: '神父は贖罪として3つの祈りを唱えるよう彼に求めた。' },
  'penoso': { es: 'Fue penoso ver cómo el equipo perdió el partido en los últimos segundos.', ja: 'チームが最後の数秒で試合を落とすのを見るのは痛ましかった。' },
  'pensamiento': { es: 'El libro explora los pensamientos más profundos de un filósofo medieval.', ja: 'その本は中世の哲学者の最も深い思想を探求している。' },
