  'penumbra': { es: 'La habitación estaba en penumbra y apenas se podían distinguir los muebles.', ja: '部屋は薄暗く、家具がかろうじて見分けられる程度だった。' },
  'pepino': { es: 'Añadí pepino y tomate a la ensalada para que quedara más fresca.', ja: 'サラダをよりさっぱりさせるためにキュウリとトマトを加えた。' },
  'pepita': { es: 'Los niños sacaron las pepitas de la sandía antes de comerla.', ja: '子供たちはスイカを食べる前に種を取り出した。' },
  'pera': { es: 'Me comí una pera madura después del almuerzo.', ja: '昼食の後、熟した洋ナシを一つ食べた。' },
  'percance': { es: 'Llegué tarde a la reunión por un pequeño percance en el camino.', ja: '途中で小さなトラブルがあって、会議に遅刻してしまった。' },
  'percibir': { es: 'Percibo un ligero olor a gas en la cocina.', ja: '台所でかすかなガスの匂いに気づく。' },
  'percha': { es: 'Cuelga el abrigo en la percha antes de entrar al salón.', ja: '居間に入る前にコート掛けにコートを掛けてください。' },
  'perdición': { es: 'El juego fue su perdición y acabó arruinándose.', ja: 'ギャンブルが彼の破滅のもとになり、最終的に身を滅ぼした。' },
  'pérdida': { es: 'La empresa sufrió grandes pérdidas durante la crisis económica.', ja: 'その企業は経済危機の間に大きな損失を被った。' },
  'perdido': { es: 'Estaba completamente perdido en aquella ciudad que no conocía.', ja: '知らない街で完全に道に迷っていた。' },
  'perdón': { es: 'Le pedí perdón por haber llegado tarde a su fiesta.', ja: '彼のパーティーに遅刻したことを謝った。' },
  'perdonar': { es: 'Es difícil perdonar a quien te ha traicionado.', ja: '自分を裏切った人を許すのは難しい。' },
  'perdurar': { es: 'El recuerdo de ese viaje perdurará en mi memoria para siempre.', ja: 'あの旅の思い出は永遠に記憶の中に残り続けるだろう。' },
