  'pereza': { es: 'La pereza no te dejará alcanzar tus metas.', ja: '怠惰ではあなたの目標を達成できないだろう。' },
  'perezoso': { es: 'El perezoso pasa la mayor parte de su vida colgado en los árboles.', ja: 'ナマケモノは生涯の大半を木にぶら下がって過ごす。' },
