  'perfil': { es: 'Te reconocí de lejos solo por tu perfil.', ja: '横顔だけで遠くからあなただとわかった。' },
  'perfume': { es: 'El perfume de las rosas llenaba todo el jardín.', ja: 'バラの香りが庭全体に漂っていた。' },
  'pericia': { es: 'La pericia del cirujano fue determinante para el éxito de la operación.', ja: '外科医の熟練した技術が手術の成功に決定的な役割を果たした。' },
  'periferia': { es: 'Muchas familias jóvenes se trasladan a la periferia de las ciudades.', ja: '多くの若い家族が都市の郊外に移住する。' },
