  'periodismo': { es: 'El periodismo de investigación es fundamental para mantener la democracia.', ja: '調査報道は民主主義を維持するために不可欠だ。' },
  'período': { es: 'Durante el período de la guerra civil, muchas familias tuvieron que emigrar.', ja: '内戦の時期には、多くの家族が移住せざるを得なかった。' },
  'perjuicio': { es: 'Fumar en exceso causa un grave perjuicio para la salud.', ja: '過度な喫煙は健康に深刻な害をもたらす。' },
  'perjudicial': { es: 'El exceso de azúcar es perjudicial para los dientes de los niños.', ja: '砂糖の過剰摂取は子どもの歯に有害だ。' },
