  'perla': { es: 'Me regalaron un collar de perlas para mi graduación.', ja: '卒業のお祝いに真珠のネックレスをもらった。' },
  'permanecer': { es: 'Decidimos permanecer en casa durante la tormenta.', ja: '嵐の間は家に留まることにした。' },
  'permanencia': { es: 'La permanencia del equipo en la primera división depende de los próximos partidos.', ja: 'そのチームの一部リーグ残留は今後の試合にかかっている。' },
  'permanente': { es: 'El daño al medioambiente puede ser permanente si no actuamos ahora.', ja: '今行動しなければ、環境への損害は恒久的なものになりかねない。' },
