  'permuta': { es: 'Ambos profesores acordaron una permuta para poder trabajar en sus ciudades natales.', ja: '両教員は故郷の都市で働けるよう転勤の交換に合意した。' },
  'permutar': { es: 'Los dos funcionarios decidieron permutar sus puestos para estar más cerca de sus familias.', ja: '2人の公務員は家族のそばにいるために職位を交換することにした。' },
  'pernoctar': { es: 'Los excursionistas decidieron pernoctar en una cabaña de montaña.', ja: 'ハイカーたちは山小屋で一泊することにした。' },
  'pero': { es: 'Quería ir a la playa, pero empezó a llover.', ja: '海に行きたかったが、雨が降り始めた。' },
  'persecución': { es: 'La persecución policial terminó cuando el sospechoso se entregó voluntariamente.', ja: '容疑者が自ら出頭したことで警察の追跡は終わった。' },
  'perseguir': { es: 'La policía persiguió al ladrón por las calles del centro.', ja: '警察は市街地の通りで泥棒を追いかけた。' },
  'perseverancia': { es: 'Gracias a su perseverancia, logró terminar la carrera universitaria a pesar de las dificultades.', ja: '粘り強さのおかげで、困難にもかかわらず大学の学位課程を修了することができた。' },
  'perseverar': { es: 'Hay que perseverar en los estudios aunque a veces sea difícil.', ja: '時に困難であっても、学業に粘り強く取り組まなければならない。' },
  'persiana': { es: 'Baja la persiana para que no entre tanto sol por la mañana.', ja: '朝に日差しが入りすぎないようにブラインドを下ろして。' },
