  'persistir': { es: 'El mal tiempo persistió durante toda la semana.', ja: '悪天候が一週間ずっと続いた。' },
  'personaje': { es: 'El personaje principal de la novela es un detective retirado.', ja: 'その小説の主人公は引退した探偵だ。' },
  'personal': { es: 'El jefe de personal anunció nuevas políticas de vacaciones para todos los empleados.', ja: '人事部長が全従業員に向けた新しい休暇制度を発表した。' },
  'personalidad': { es: 'Tiene una personalidad muy extrovertida que le facilita hacer amigos.', ja: '彼女はとても外向的な性格なので、友達を作るのが容易だ。' },
  'personalizar': { es: 'La aplicación te permite personalizar la interfaz según tus preferencias.', ja: 'そのアプリはインターフェースを好みに合わせてカスタマイズできる。' },
  'perspectiva': { es: 'Desde esa perspectiva, el problema parece mucho más sencillo de resolver.', ja: 'その観点から見ると、問題はずっと簡単に解決できるように思える。' },
  'persuadir': { es: 'Al final, logré persuadir a mis padres para que me dejaran estudiar en el extranjero.', ja: '最終的に、両親を説得して海外留学を許してもらえた。' },
  'persuasión': { es: 'La persuasión es una herramienta clave en la negociación comercial.', ja: '説得は商業交渉における重要なツールだ。' },
  'pertenecer': { es: 'Este cuadro pertenece a una colección privada y nunca se ha expuesto al público.', ja: 'この絵画は個人コレクションに属しており、一般に公開されたことがない。' },
  'pertenencia': { es: 'El sentido de pertenencia a un grupo es fundamental para el bienestar emocional.', ja: '集団への帰属感は、感情的な健康にとって根本的なものだ。' },
  'pertinente': { es: 'Por favor, limita tus comentarios a los puntos pertinentes al tema de discusión.', ja: '議論のテーマに関連するポイントにコメントを絞ってください。' },
  'pertrechos': { es: 'Los soldados llegaron al frente con los pertrechos necesarios para la campaña.', ja: '兵士たちは作戦に必要な軍需品を持って前線に到着した。' },
  'perversidad': { es: 'La perversidad del personaje principal lo convierte en uno de los villanos más memorables de la literatura.', ja: '主人公の邪悪さが、彼を文学の中で最も記憶に残る悪役の一人にしている。' },
  'perverso': { es: 'El sistema tiene efectos perversos que nadie anticipó cuando fue diseñado.', ja: 'そのシステムには、設計時に誰も予想しなかった逆効果が生じている。' },
  'pesadilla': { es: 'Anoche tuve una pesadilla en la que me perseguían y no podía moverme.', ja: '昨夜、追いかけられて動けない悪夢を見た。' },
  'pesadumbre': { es: 'La noticia de su fallecimiento nos llenó de pesadumbre a todos los presentes.', ja: '彼の訃報は、その場にいた全員を深い悲しみで満たした。' },
  'pesar': { es: 'Esta maleta pesa demasiado; tendré que sacar algunas cosas antes de facturarla.', ja: 'このスーツケースは重すぎる。チェックインする前にいくつか出さなければならない。' },
  'pesca': { es: 'La pesca artesanal es una fuente de ingresos importante para muchas comunidades costeras.', ja: '伝統的な漁業は、多くの沿岸地域コミュニティにとって重要な収入源だ。' },
  'pescadería': { es: 'Compré gambas frescas en la pescadería del mercado municipal.', ja: '市場の鮮魚店で新鮮なエビを買った。' },
  'pescador': { es: 'El pescador regresó al puerto al amanecer con una buena captura.', ja: '漁師は夜明けに豊漁を携えて港へ戻った。' },
  'pescar': { es: 'Los domingos, mi abuelo y yo íbamos a pescar al río con cañas sencillas.', ja: '日曜日には、祖父と私はシンプルな竿を持って川へ釣りに行ったものだ。' },
  'pesebre': { es: 'Cada año, los niños del pueblo ayudan a montar el pesebre en la plaza central.', ja: '毎年、村の子供たちが中央広場にキリスト誕生の模型を飾る手伝いをする。' },
  'pesimismo': { es: 'El pesimismo crónico puede afectar negativamente tanto la salud mental como la física.', ja: '慢性的な悲観主義は、精神的・肉体的健康の両方に悪影響を与えうる。' },
  'pesimista': { es: 'No seas tan pesimista; todavía hay muchas posibilidades de que las cosas salgan bien.', ja: 'そんなに悲観的にならないで。まだ物事がうまくいく可能性はたくさんある。' },
  'pésimo': { es: 'La atención al cliente de esa empresa es pésima; tardaron tres semanas en responder.', ja: 'あの会社の顧客対応は最悪で、返信に3週間もかかった。' },
  'peso': { es: 'Desde que empecé a hacer ejercicio, he perdido cinco kilos de peso.', ja: '運動を始めてから、体重が5キロ落ちた。' },
  'pestañas': { es: 'Ella se aplica rímel en las pestañas antes de salir a trabajar cada mañana.', ja: '彼女は毎朝仕事に出かける前にまつげにマスカラを塗る。' },
  'peste': { es: 'La peste negra del siglo XIV acabó con un tercio de la población europea.', ja: '14世紀の黒死病はヨーロッパの人口の三分の一を死に至らしめた。' },
  'pestillo': { es: 'Asegúrate de echar el pestillo antes de acostarte para que nadie pueda entrar.', ja: '誰も入ってこられないように、寝る前に必ず鍵をかけなさい。' },
  'petaca': { es: 'Mi abuelo siempre llevaba una petaca de plata con whisky en el bolsillo del abrigo.', ja: '祖父はいつもコートのポケットにウイスキーを入れた銀のフラスコを持ち歩いていた。' },
  'petición': { es: 'La organización presentó una petición con más de diez mil firmas ante el ayuntamiento.', ja: 'その団体は市役所に1万件以上の署名を集めた請願書を提出した。' },
  'petróleo': { es: 'Los precios del petróleo han subido considerablemente en los últimos meses.', ja: 'ここ数ヶ月で石油の価格がかなり上昇した。' },
