  'picadura': { es: 'Me puse crema para aliviar la picadura de mosquito que tenía en el brazo.', ja: '腕についた蚊に刺された跡を和らげるためにクリームを塗った。' },
  'picar': { es: 'A mí me picó una avispa mientras trabajaba en el jardín.', ja: '庭で作業中にスズメバチに刺された。' },
