  'pilar': { es: 'La educación es uno de los pilares fundamentales de cualquier sociedad democrática.', ja: '教育は民主主義社会のあらゆる基盤の一つだ。' },
  'píldora': { es: 'El médico le recetó una píldora antiinflamatoria que debe tomar dos veces al día.', ja: '医師は1日2回服用する抗炎症薬の錠剤を処方した。' },
  'piloto': { es: 'La piloto aterrizó el avión con gran precisión a pesar de la tormenta.', ja: 'パイロットは嵐にもかかわらず、高い精度で飛行機を着陸させた。' },
