  'pinacoteca': { es: 'La Pinacoteca de Brera en Milán alberga algunas de las obras maestras del Renacimiento italiano.', ja: 'ミラノのブレラ絵画館はイタリア・ルネサンスの傑作を数多く収蔵している。' },
  'pincel': { es: 'El artista limpió el pincel con cuidado antes de cambiar de color.', ja: '芸術家は色を変える前に丁寧に絵筆を洗った。' },
